SELECT shape_name, created_date, status
FROM shapes
ORDER BY created_date DESC;

SELECT SUM(file_size) AS total_file_size
  FROM shape_files
  WHERE created_by = 1;

SELECT shape_name 
FROM shapes 
ORDER BY shape_name;

SELECT shape_name
FROM shapes
ORDER BY created_date, shape_name;

SELECT shape_name 
FROM shapes 
ORDER BY shape_name;

SELECT shape_name, created_date
FROM shapes
ORDER BY created_date DESC;

SELECT shape_name
FROM shapes
ORDER BY last_modified_date DESC, shape_id ASC;

SELECT shape_name, created_date
FROM shapes
WHERE shape_id = 0 AND category_id = 1;

SELECT file_path, file_size
FROM shape_files
ORDER BY upload_date DESC;
